+
+/// Get or create event loop
+fn getEventLoop() !*EventLoop {
+    if (global_loop == null) {
+        const loop = try global_allocator.create(EventLoop);
+        loop.* = try EventLoop.init(global_allocator);
+        global_loop = loop;
+    }
+    return global_loop.?;
+}
