+/// asyncio.sleep(seconds) - Async sleep
+pub fn sleep(allocator: std.mem.Allocator, seconds: f64) !*runtime.PyObject {
+    const loop = try getEventLoop();
+
+    const delay_ns: i64 = @intFromFloat(seconds * @as(f64, std.time.ns_per_s));
